  function getPerspectiveFormationSwitchAcknowledgementContext(
    basis: FormationSwitchAcknowledgedBasis,
  ): FormationSwitchAcknowledgementContext | null {
    if (
      !perspectiveConstellationFormationReceipt ||
      !perspectiveIngestConstellationPreview ||
      !perspectiveIngestConstellation
    ) {
      return null;
    }

    const selectedNodeId =
      basis === "manual_selection"
        ? explicitSelectedPerspectiveIngestNode?.id ?? null
        : null;
    if (basis === "manual_selection" && !selectedNodeId) {
      return null;
    }

    const targetScope =
      basis === "manual_selection" ? "manual_selection" : "whole_constellation";
    const sourceQuery = perspectiveIngestConstellationPreview.meta.source_query;
    const constellationId =
      perspectiveConstellationFormationReceipt.constellation_id;
    const formationId = buildPerspectiveFormationSwitchFormationId({
      constellationId,
      selectedNodeId,
      sourceQuery,
      targetScope,
    });
    const contextFingerprint = buildFormationSwitchContextFingerprint([
      "Formation Basis",
      FORMATION_SWITCH_BASIS_VERSION,
      basis,
      targetScope,
      sourceQuery,
      constellationId,
      perspectiveIngestConstellationPreview.meta.generated_at,
      perspectiveIngestConstellation.nodes.length,
      perspectiveIngestConstellation.edges.length,
      selectedNodeId,
    ]);

    return {
      basis,
      basisVersion: FORMATION_SWITCH_BASIS_VERSION,
      sourceQuery,
      constellationId,
      formationId,
      contextFingerprint,
    };
  }

  function hasValidFormationSwitchAcknowledgement(
    basis: FormationSwitchAcknowledgedBasis,
  ) {
    const context = getPerspectiveFormationSwitchAcknowledgementContext(basis);
    if (!context) return false;

    const storedAcknowledgement =
      readFormationSwitchAcknowledgementFromStorage();
    if (!storedAcknowledgement.available) return false;

    return formationSwitchAcknowledgementIsValid({
      acknowledgement: storedAcknowledgement.acknowledgement,
      context,
    });
  }

  function getPerspectiveFormationBasisSwitchDecision(
    basis: PerspectiveFormationBasisExplanationCandidate,
  ): PerspectiveFormationBasisSwitchDecision {
    if (!isPerspectiveFormationLocalSwitchBasis(basis)) {
      return "show_future_explanation";
    }

    if (hasValidFormationSwitchAcknowledgement(basis)) {
      return "apply_immediately";
    }

    if (
      basis === "current" &&
      perspectiveConstellationSelectionScope === "whole_constellation" &&
      perspectiveConstellationFormationReceipt?.formation_basis === "current"
    ) {
      return "already_active";
    }

    if (
      basis === "manual_selection" &&
      perspectiveConstellationSelectionScope === "manual_selection" &&
      perspectiveConstellationFormationReceipt?.formation_basis ===
        "manual_selection"
    ) {
      return "already_active";
    }

    return "show_switch_overlay";
  }

  function handlePerspectiveFormationBasisControlClick(
    basis: PerspectiveFormationBasisExplanationCandidate,
  ) {
    formationSwitchTriggerBasisRef.current = basis;
    setSelectedFormationBasisExplanation(basis);
    setFormationBasisExplanationOpen(true);
    setManualGravityDraftOverwritePending(null);

    const decision = getPerspectiveFormationBasisSwitchDecision(basis);
    if (decision === "show_future_explanation") {
      setPendingFormationBasisSwitch(basis);
      setFormationSwitchOverlayOpen(true);
      setFormationSwitchNotice({
        tone: "info",
        text: `${getPerspectiveFormationBasisLabel(basis)} is explanation-only · future behavior`,
      });
      return;
    }

    if (decision === "already_active") {
      setPendingFormationBasisSwitch(null);
      setFormationSwitchOverlayOpen(false);
      setFormationSwitchNotice({
        tone: "info",
        text:
          basis === "manual_selection"
            ? "Already viewing Manual Selection"
            : "Already viewing Current",
      });
      return;
    }

    if (decision === "apply_immediately") {
      if (isPerspectiveFormationLocalSwitchBasis(basis)) {
        applyPerspectiveFormationBasisSwitch(basis, "cached");
      }
      return;
    }

    setPendingFormationBasisSwitch(basis);
    setFormationSwitchOverlayOpen(true);
    setFormationSwitchNotice(null);
  }

  function closePerspectiveFormationBasisSwitchOverlay() {
    setPendingFormationBasisSwitch(null);
    setFormationSwitchOverlayOpen(false);
  }

  function applyPendingPerspectiveFormationBasisSwitch() {
    if (!pendingFormationBasisSwitch) return;
    if (!isPerspectiveFormationLocalSwitchBasis(pendingFormationBasisSwitch)) {
      closePerspectiveFormationBasisSwitchOverlay();
      return;
    }

    applyPerspectiveFormationBasisSwitch(pendingFormationBasisSwitch, "overlay");
  }

  function applyPerspectiveFormationBasisSwitch(
    basis: FormationSwitchAcknowledgedBasis,
    source: "overlay" | "cached",
  ) {
    const acknowledgementContext =
      getPerspectiveFormationSwitchAcknowledgementContext(basis);

    if (basis === "manual_selection" && !explicitSelectedPerspectiveIngestNode) {
      setPendingFormationBasisSwitch("manual_selection");
      setFormationSwitchOverlayOpen(true);
      setFormationSwitchNotice({
        tone: "error",
        text: "Select a node or cluster before applying Manual Selection.",
      });
      return;
    }

    if (basis === "current") {
      // Formation Basis controls how the local preview was formed; scope helpers
      // own the graph-material transition details.
      selectWholeConstellationScope({ syncLens: "whole_constellation" });
    } else {
      selectManualSelectionScope();
    }

    setSelectedFormationBasisExplanation(basis);
    setSelectedEventRailEntry("current_view");
    setPerspectiveIngestCopyNotice(null);
    setManualGravityDraftOverwritePending(null);
    setPendingFormationBasisSwitch(null);
    setFormationSwitchOverlayOpen(false);

    if (source === "overlay" && acknowledgementContext) {
      writeFormationSwitchAcknowledgementToStorage(
        buildFormationSwitchAcknowledgement({
          context: acknowledgementContext,
        }),
      );
    }

    setFormationSwitchNotice({
      tone: "info",
      text:
        source === "cached"
          ? basis === "manual_selection"
            ? "Viewing Manual Selection · cached local acknowledgement · no API call"
            : "Viewing Current · cached local acknowledgement · no API call"
          : basis === "manual_selection"
            ? "Applied Manual Selection View · local-only"
            : "Applied Current View · local-only",
    });
  }

  function selectPerspectiveLensOnly(lens: PerspectiveConstellationLens) {
    setSelectedPerspectiveConstellationLens(lens);
    setPerspectiveIngestCopyNotice(null);
    setManualGravityDraftOverwritePending(null);
  }

  function applyPerspectiveScope(
    scope: PerspectiveConstellationSelectionScope,
    options: PerspectiveScopeTransitionOptions = {},
  ) {
    setPerspectiveConstellationSelectionScope(scope);

    if (Object.prototype.hasOwnProperty.call(options, "nodeId")) {
      setSelectedPerspectiveIngestNodeId(options.nodeId ?? null);
    } else if (options.clearNode) {
      setSelectedPerspectiveIngestNodeId(null);
    }

    if (Object.prototype.hasOwnProperty.call(options, "clusterId")) {
      setSelectedPerspectiveIngestClusterId(options.clusterId ?? null);
    } else if (options.clearCluster) {
      setSelectedPerspectiveIngestClusterId(null);
    }

    if (options.packetTarget) {
      setPerspectiveHandoffTarget(options.packetTarget);
    }

    if (options.syncLens) {
      selectPerspectiveLensOnly(options.syncLens);
    }

    if (Object.prototype.hasOwnProperty.call(options, "notice")) {
      setPerspectiveIngestCopyNotice(options.notice ?? null);
    } else {
      setPerspectiveIngestCopyNotice(null);
    }
    setManualGravityDraftOverwritePending(null);
  }

  function selectWholeConstellationScope(
    options: PerspectiveScopeTransitionOptions = {},
  ) {
    applyPerspectiveScope("whole_constellation", {
      ...options,
      clearNode: true,
      clearCluster: true,
    });
  }

  function selectConnectedNodeScope(
    options: PerspectiveScopeTransitionOptions = {},
  ) {
    const nodeId =
      options.nodeId ??
      explicitSelectedPerspectiveIngestNode?.id ??
      perspectiveIngestConstellation?.nodes[0]?.id ??
      null;

    applyPerspectiveScope("connected_node", {
      ...options,
      nodeId,
      clearCluster: true,
    });
  }

  function selectPerspectiveNodeScope(nodeId: string) {
    selectConnectedNodeScope({
      nodeId,
      syncLens: "connected_nodes",
    });
  }

  function selectClusterScope(options: PerspectiveScopeTransitionOptions = {}) {
    const clusterId =
      options.clusterId ??
      selectedPerspectiveIngestCluster?.id ??
      perspectiveConstellationWorkspaceCluster?.id ??
      null;

    if (!clusterId) {
      applyPerspectiveScope("cluster", {
        ...options,
        clearNode: true,
        clusterId: null,
      });
      return;
    }

    selectPerspectiveClusterScope(clusterId, options);
  }

  function selectPerspectiveClusterScope(
    clusterId: string,
    options: PerspectiveScopeTransitionOptions = {},
  ) {
    applyPerspectiveScope("cluster", {
      ...options,
      clusterId,
      clearNode: true,
    });
  }

  function selectManualSelectionScope(
    options: PerspectiveManualSelectionScopeOptions = {},
  ) {
    const { allowPreviewFallback = false, ...scopeOptions } = options;
    const selectedNodeId = explicitSelectedPerspectiveIngestNode?.id ?? null;
    const selectedClusterId = selectedPerspectiveIngestCluster?.id ?? null;

    if (!selectedNodeId && !selectedClusterId && !allowPreviewFallback) {
      setPerspectiveIngestCopyNotice({
        tone: "info",
        text: "Select a node or cluster before using Manual Selection.",
      });
      setManualGravityDraftOverwritePending(null);
      return false;
    }

    // Manual Selection scope is local preview context, not durable
    // FormationReceipt authority.
    applyPerspectiveScope("manual_selection", {
      ...scopeOptions,
      ...(selectedNodeId
        ? { nodeId: selectedNodeId, clearCluster: true }
        : selectedClusterId
          ? { clusterId: selectedClusterId, clearNode: true }
          : {}),
    });
    return true;
  }

  function setPerspectiveHandoffTarget(target: PerspectiveIngestPacketTarget) {
    setSelectedPerspectiveIngestPacketTarget(target);
  }

  function handlePerspectiveLensControlClick(lens: PerspectiveConstellationLens) {
    if (lens === "whole_constellation") {
      selectWholeConstellationScope({ syncLens: "whole_constellation" });
      return;
    }

    if (lens === "connected_nodes") {
      selectConnectedNodeScope({ syncLens: "connected_nodes" });
      return;
    }

    if (lens === "open_tensions") {
      // Open Tensions does not have a dedicated scope yet; this keeps the
      // previous local inspection fallback explicit.
      selectManualSelectionScope({
        syncLens: "open_tensions",
        allowPreviewFallback: true,
      });
      return;
    }

    if (lens === "next_candidates") {
      // Next Candidates does not have a dedicated scope yet; manual_selection is
      // the current local preview fallback.
      selectManualSelectionScope({
        syncLens: "next_candidates",
        allowPreviewFallback: true,
      });
      return;
    }

    selectPerspectiveLensOnly("codex_handoff");
    setPerspectiveHandoffTarget("codex_handoff");
  }

  function inspectPerspectiveConstellationConnectedNodes() {
    selectConnectedNodeScope({ syncLens: "connected_nodes" });
  }

  function previewPerspectiveConstellationUnit() {
    selectClusterScope({ packetTarget: "chatgpt_review" });
  }

  function markPerspectiveConstellationNextCandidatePreview() {
    selectManualSelectionScope({
      syncLens: "next_candidates",
      allowPreviewFallback: true,
      notice: {
        tone: "info",
        text: "Marked as next candidate preview",
      },
    });
  }

  function openPerspectiveConstellationHandoffPacket() {
    setHandoffPacketOpen(true);
    setPerspectiveHandoffTarget("codex_handoff");
    setPerspectiveIngestCopyNotice(null);
  }

  function applyManualGravityPreview() {
    if (!hasManualGravityDraftableMarks) return;
    setAppliedGravityPreviewActive(true);
  }

  function resetManualGravityPreviewApplication() {
    setAppliedGravityPreviewActive(false);
  }

  function commitManualGravityLocalDraft(draft: ManualGravityLocalDraft) {
    if (!writeManualGravityLocalDraftToStorage(draft)) {
      setManualGravityLocalDraftStatus("unavailable");
      setManualGravityLocalDraftReceipt(null);
      setManualGravityLocalDraftStorageSnapshot({
        available: false,
        rawDraftPresent: false,
        draft: null,
        malformed: false,
        unsafeMarksIgnored: false,
      });
      setManualGravityDraftOverwritePending(null);
      return false;
    }

    restoredManualGravityLocalDraftContextRef.current =
      manualGravityLocalDraftContextKey;
    setManualGravityLocalDraftReceipt(getManualGravityLocalDraftReceipt(draft));
    setManualGravityLocalDraftStorageSnapshot({
      available: true,
      rawDraftPresent: true,
      draft,
      malformed: false,
      unsafeMarksIgnored: false,
    });
    setManualGravityDraftOverwritePending(null);
    setManualGravityLocalDraftStatus("saved_for_this_formation");
    return true;
  }

  function saveManualGravityLocalDraftMarks() {
    if (
      !manualGravityLocalDraftContext ||
      !hasManualGravityPreviewMarks(selectedGravityPreviewMarks)
    ) {
      setManualGravityLocalDraftStatus(
        manualGravityLocalDraftContext ? "unsaved" : "unavailable",
      );
      setManualGravityLocalDraftReceipt(null);
      setManualGravityLocalDraftStorageSnapshot(
        manualGravityLocalDraftContext
          ? {
              available: true,
              rawDraftPresent: false,
              draft: null,
              malformed: false,
              unsafeMarksIgnored: false,
            }
          : null,
      );
      setManualGravityDraftOverwritePending(null);
      return;
    }

    const draft = {
      version: MANUAL_GRAVITY_LOCAL_DRAFT_VERSION,
      ...manualGravityLocalDraftContext,
      marks_by_target: sanitizeManualGravityPreviewMarks(
        selectedGravityPreviewMarks,
      ),
      saved_at: new Date().toISOString(),
    } satisfies ManualGravityLocalDraft;

    const existingManualGravityLocalDraft =
      readManualGravityLocalDraftFromStorage();
    setManualGravityLocalDraftStorageSnapshot(existingManualGravityLocalDraft);
    if (!existingManualGravityLocalDraft.available) {
      setManualGravityLocalDraftStatus("unavailable");
      setManualGravityLocalDraftReceipt(null);
      setManualGravityDraftOverwritePending(null);
      return;
    }

    if (existingManualGravityLocalDraft.rawDraftPresent) {
      setManualGravityDraftOverwritePending({
        existingReceipt: getManualGravityLocalDraftOverwriteReceipt(
          existingManualGravityLocalDraft,
        ),
        newDraft: draft,
        newReceipt: getManualGravityLocalDraftReceipt(draft),
      });
      return;
    }

    commitManualGravityLocalDraft(draft);
  }

  function replaceManualGravityLocalDraftMarks() {
    if (!manualGravityDraftOverwritePending) return;

    commitManualGravityLocalDraft(manualGravityDraftOverwritePending.newDraft);
  }

  function cancelManualGravityLocalDraftOverwrite() {
    setManualGravityDraftOverwritePending(null);
  }

  function clearManualGravityLocalDraftMarks() {
    if (!clearManualGravityLocalDraftStorage()) {
      setManualGravityLocalDraftStatus("unavailable");
      setManualGravityLocalDraftReceipt(null);
      setManualGravityLocalDraftStorageSnapshot({
        available: false,
        rawDraftPresent: false,
        draft: null,
        malformed: false,
        unsafeMarksIgnored: false,
      });
      setManualGravityDraftOverwritePending(null);
      return;
    }

    restoredManualGravityLocalDraftContextRef.current = null;
    setSelectedGravityPreviewMarks({});
    setManualGravityLocalDraftReceipt(null);
    setManualGravityLocalDraftStorageSnapshot(null);
    setManualGravityDraftOverwritePending(null);
    setAppliedGravityPreviewActive(false);
    setManualGravityLocalDraftStatus("cleared");
  }

  function toggleManualGravityPreviewMark(mark: ManualGravityPreviewMark) {
    if (!manualGravityPreviewSelection) return;

    const selectionKey = manualGravityPreviewSelection.key;
    setManualGravityLocalDraftStatus(
      manualGravityLocalDraftContext ? "unsaved_changes" : "unavailable",
    );
    setManualGravityLocalDraftReceipt(null);
    setManualGravityDraftOverwritePending(null);
    setAppliedGravityPreviewActive(false);
    setSelectedGravityPreviewMarks((currentMarks) => {
      const currentSelectionMarks = currentMarks[selectionKey] ?? [];
      const nextSelectionMarks = currentSelectionMarks.includes(mark)
        ? currentSelectionMarks.filter((currentMark) => currentMark !== mark)
        : [...currentSelectionMarks, mark];

      if (nextSelectionMarks.length === 0) {
        const { [selectionKey]: _removedSelection, ...remainingMarks } =
          currentMarks;
        return remainingMarks;
      }

      return {
        ...currentMarks,
        [selectionKey]: nextSelectionMarks,
      };
    });
  }

  function clearManualGravityPreviewMarks() {
    if (!manualGravityPreviewSelection) return;

    const selectionKey = manualGravityPreviewSelection.key;
    setManualGravityLocalDraftStatus(
      manualGravityLocalDraftContext ? "unsaved_changes" : "unavailable",
    );
    setManualGravityLocalDraftReceipt(null);
    setManualGravityDraftOverwritePending(null);
    setAppliedGravityPreviewActive(false);
    setSelectedGravityPreviewMarks((currentMarks) => {
      const { [selectionKey]: _removedSelection, ...remainingMarks } =
        currentMarks;
      return remainingMarks;
    });
  }

  function refreshPerspectiveIngestConstellationPreview(
    source: PerspectiveIngestSourceSelection,
  ) {
    setSelectedPerspectiveIngestSource(source);
    setPerspectiveIngestPreviewMode("sample fixture preview");
    setPerspectiveHandoffTarget(
      source === "sample:chatgpt" ? "chatgpt_review" : "codex_handoff",
    );
    setPerspectiveIngestCopyNotice(null);
    setPerspectiveConstellationSelectionScope("whole_constellation");
    setSelectedPerspectiveConstellationLens("whole_constellation");
    setSelectedEventRailEntry("current_view");
    setFormationBasisExplanationOpen(false);
    setSelectedFormationBasisExplanation("current");
    setSelectedGravityPreviewMarks({});
    setManualGravityLocalDraftStatus("unsaved");
    setManualGravityLocalDraftReceipt(null);
    setManualGravityLocalDraftStorageSnapshot(null);
    setManualGravityDraftOverwritePending(null);
    setAppliedGravityPreviewActive(false);
    setSelectedPerspectiveIngestNodeId(null);
    setSelectedPerspectiveIngestClusterId(null);
    setPerspectiveIngestConstellationPreviewState({ status: "loading" });
    void fetchPerspectiveIngestConstellationPreview(source).then((result) => {
      setPerspectiveIngestConstellationPreviewState(result);
    });
  }

  function loadSafePastedTextExample() {
    setManualPastedText(SAFE_PASTED_TEXT_EXAMPLE);
    setManualPastedTextSourceLabel("Safe manual pasted text example");
    setPerspectiveIngestCopyNotice(null);
  }

  function clearManualPastedText() {
    setManualPastedText("");
    setManualPastedTextSourceLabel("");
    setPerspectiveIngestCopyNotice(null);
  }

  function previewManualPastedText(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    previewManualPastedTextFromForm(event.currentTarget);
  }

  function previewManualPastedTextFromForm(form: HTMLFormElement | null) {
    const pastedTextInput =
      form?.querySelector<HTMLTextAreaElement>(
        "#perspective-ingest-local-pasted-text",
      )?.value ?? manualPastedText;
    const sourceLabelInput =
      form?.querySelector<HTMLInputElement>(
        "#perspective-ingest-local-source-label",
      )?.value ?? manualPastedTextSourceLabel;

    setPerspectiveIngestPreviewMode("manual pasted text preview");
    setPerspectiveHandoffTarget("chatgpt_review");
    setPerspectiveIngestCopyNotice(null);
    setPerspectiveConstellationSelectionScope("whole_constellation");
    setSelectedPerspectiveConstellationLens("whole_constellation");
    setSelectedEventRailEntry("current_view");
    setFormationBasisExplanationOpen(false);
    setSelectedFormationBasisExplanation("current");
    setSelectedGravityPreviewMarks({});
    setManualGravityLocalDraftStatus("unsaved");
    setManualGravityLocalDraftReceipt(null);
    setManualGravityLocalDraftStorageSnapshot(null);
    setManualGravityDraftOverwritePending(null);
    setAppliedGravityPreviewActive(false);
    setSelectedPerspectiveIngestNodeId(null);
    setSelectedPerspectiveIngestClusterId(null);

    if (!pastedTextInput.trim()) {
      setManualGravityLocalDraftStatus("unavailable");
      setManualGravityLocalDraftReceipt(null);
      setManualGravityLocalDraftStorageSnapshot(null);
      setManualGravityDraftOverwritePending(null);
      setAppliedGravityPreviewActive(false);
      setPerspectiveIngestConstellationPreviewState({
        status: "failed",
        error: PERSPECTIVE_INGEST_MISSING_INPUT_ERROR,
      });
      return;
    }

    setPerspectiveIngestConstellationPreviewState({ status: "loading" });
    void fetchPerspectiveIngestLocalPastedTextPreview({
      inputText: pastedTextInput,
      sourceLabel: sourceLabelInput,
    }).then((result) => {
      if (result.status === "failed" && result.error.code === "secret_like_input") {
        setManualPastedText("");
      }
      setPerspectiveIngestConstellationPreviewState(result);
    });
  }

  async function copyConstellationCodexHandoff(handoffText: string) {
    try {
      await copyTextToClipboard(handoffText);
      setConstellationHandoffCopyNotice({
        tone: "info",
        text: "Copied",
      });
    } catch (copyError) {
      setConstellationHandoffCopyNotice({
        tone: "error",
        text:
          copyError instanceof Error
            ? copyError.message
            : "Copy Codex handoff failed",
      });
    }
  }

