function PendingProposalQueuePanel({
  proposals,
  busy,
  onConsolidateCandidates,
  onDecideProposal,
}: PendingProposalQueueProps) {
  return (
    <section className="cockpit-surface-card proposals-panel">
      <PanelHeader eyebrow="Operator" title="Pending local state proposal queue" />
      <div className="panel-control-row">
        <p>
          Local runtime proposals only. Commit/Reject writes only local Augnes
          state through the existing proposal gate.
        </p>
        <button
          type="button"
          className="secondary-button"
          onClick={onConsolidateCandidates}
          disabled={busy === "consolidate"}
        >
          Consolidate Candidates
        </button>
      </div>
      <div className="proposal-list">
        {proposals.length === 0 ? (
          <EmptyState
            label="No pending proposals."
            description="Use Observe advanced input to generate local state candidates."
          />
        ) : (
          proposals.map((proposal) => (
            <article className="proposal-card" key={proposal.id}>
              <div className="card-topline">
                <div className="state-key-heading">
                  <h3>{formatStateKeyLabel(proposal.state_key)}</h3>
                  <code>{proposal.state_key}</code>
                </div>
                <StatusBadge
                  label={formatStatusLabel(proposal.consolidation_status)}
                  tone={getConsolidationTone(proposal.consolidation_status)}
                />
              </div>
              <p className="consolidation-copy">
                {getConsolidationExplanation(proposal.consolidation_status)}
              </p>
              <ValueDiff
                beforeValue={proposal.before_value}
                afterValue={proposal.after_value}
              />
              <ProposalScoring proposal={proposal} />
              <div className="meta-row">
                <span>{formatStatusLabel(proposal.operation)}</span>
                <span>{formatStatusLabel(proposal.temporal_scope)}</span>
                <span>{formatStatusLabel(proposal.stability)}</span>
                <span>{formatStatusLabel(proposal.change_type)}</span>
              </div>
              {proposal.reason ? <p>{proposal.reason}</p> : null}
              <div className="button-row">
                <button
                  type="button"
                  onClick={() => onDecideProposal(proposal.id, "commit")}
                  disabled={
                    busy === proposal.id ||
                    proposal.consolidation_status === "expired"
                  }
                >
                  Commit local state proposal
                </button>
                <button
                  type="button"
                  className="secondary-button danger-outline-button"
                  onClick={() => onDecideProposal(proposal.id, "reject")}
                  disabled={busy === proposal.id}
                >
                  Reject local state proposal
                </button>
              </div>
            </article>
          ))
        )}
      </div>
    </section>
  );
}

function SafeLocalActions({
  busy,
  evidencePackLoaded,
  sessionTraceLoaded,
  sessionTraceBusy,
  plan,
  onRequestPlan,
  onRunTool,
  onLoadEvidencePack,
  onRefreshSessionTrace,
}: {
  busy: string | null;
  evidencePackLoaded: boolean;
  sessionTraceLoaded: boolean;
  sessionTraceBusy: boolean;
  plan: PlanResponse | null;
  onRequestPlan: () => void;
  onRunTool: (toolName: string) => void;
  onLoadEvidencePack: () => void;
  onRefreshSessionTrace: () => void;
}) {
  return (
    <section className="cockpit-surface-card actions-panel">
      <PanelHeader eyebrow="Operator actions (safe)" title="Safe local actions" />
      <div className="action-controls">
        <button type="button" onClick={onRequestPlan} disabled={busy === "plan"}>
          Plan Next
        </button>
        <button
          type="button"
          className="secondary-button"
          onClick={onLoadEvidencePack}
          disabled={busy === "evidence-pack"}
        >
          {evidencePackLoaded ? "Reload Evidence Pack" : "Load Evidence Pack"}
        </button>
        <button
          type="button"
          className="secondary-button"
          onClick={onRefreshSessionTrace}
          disabled={sessionTraceBusy}
        >
          {sessionTraceLoaded ? "Refresh Session Trace" : "Load Session Trace"}
        </button>
        <button
          type="button"
          className="secondary-button"
          onClick={() => onRunTool("create_readme_checklist")}
          disabled={busy === "create_readme_checklist"}
        >
          README Checklist
        </button>
        <button
          type="button"
          className="secondary-button"
          onClick={() => onRunTool("create_security_checklist")}
          disabled={busy === "create_security_checklist"}
        >
          Security Checklist
        </button>
        <button
          type="button"
          className="secondary-button"
          onClick={() => onRunTool("create_demo_script")}
          disabled={busy === "create_demo_script"}
        >
          Demo Script
        </button>
      </div>
      {plan ? (
        <div className="plan-list">
          {plan.recommendations.map((recommendation) => (
            <article className="plan-item" key={recommendation.title}>
              <div className="card-topline">
                <h3>{recommendation.title}</h3>
                <StatusBadge label={recommendation.priority} />
              </div>
              <p>{recommendation.rationale}</p>
              <div className="meta-row">
                {recommendation.tool_name ? (
                  <span>{formatStateKeyLabel(recommendation.tool_name)}</span>
                ) : null}
                {recommendation.grounded_state_keys.map((key) => (
                  <span key={key}>
                    {formatStateKeyLabel(key)} <code>{key}</code>
                  </span>
                ))}
              </div>
            </article>
          ))}
        </div>
      ) : (
        <EmptyState label="No plan requested" />
      )}
    </section>
  );
}

function RefChipList({
  refs,
  emptyLabel,
}: {
  refs: readonly string[];
  emptyLabel: string;
}) {
  const uniqueRefs = Array.from(new Set(refs.filter(Boolean))).slice(0, 18);

  if (uniqueRefs.length === 0) {
    return <EmptyState label={emptyLabel} />;
  }

  return (
    <div className="meta-row">
      {uniqueRefs.map((ref) => (
        <span key={ref}>
          <code>{ref}</code>
        </span>
      ))}
    </div>
  );
}

function TensionList({
  title,
  items,
  emptyLabel,
  maxItems = 8,
}: {
  title: string;
  items: {
    key: string;
    label: string;
    detail?: string;
    metaChips?: string[];
    fields?: { label: string; value: string }[];
  }[];
  emptyLabel: string;
  maxItems?: number;
}) {
  return (
    <section className="perspective-tension-list">
      <h3>{title}</h3>
      {items.length === 0 ? (
        <EmptyState label={emptyLabel} />
      ) : (
        <div className="compact-list">
          {items.slice(0, maxItems).map((item) => (
            <article className="tension-diagnostic-card" key={item.key}>
              <header className="tension-card-header">
                <strong className="tension-card-title">{item.label}</strong>
                {item.metaChips?.length ? (
                  <div className="tension-chip-row" aria-label="Tension metadata">
                    {item.metaChips.map((chip) => (
                      <span className="tension-chip" key={chip}>
                        {chip}
                      </span>
                    ))}
                  </div>
                ) : null}
              </header>
              <div className="tension-card-body">
                {item.fields?.length ? (
                  item.fields.map((field) => (
                    <div className="tension-card-field" key={field.label}>
                      <span className="tension-field-label">{field.label}</span>
                      <p>{field.value}</p>
                    </div>
                  ))
                ) : item.detail ? (
                  <p>{item.detail}</p>
                ) : null}
              </div>
            </article>
          ))}
        </div>
      )}
    </section>
  );
}

function PerspectiveIngestConstellationGraph({
  edges,
  gravityPreviewNodeMarksById = {},
  nodes,
  onSelectNode,
  selectedNodeId,
  surface = "preview",
}: {
  nodes: PerspectiveIngestConstellationNode[];
  edges: PerspectiveIngestConstellationEdge[];
  selectedNodeId: string | null;
  onSelectNode: (nodeId: string) => void;
  surface?: "preview" | "workspace";
  gravityPreviewNodeMarksById?: Record<string, ManualGravityPreviewMark[]>;
}) {
  const workspace = surface === "workspace";
  const width = workspace ? 1080 : 840;
  const height = workspace ? 560 : 420;
  const centerX = width / 2;
  const centerY = height / 2;
  const radiusX = workspace ? 410 : 315;
  const radiusY = workspace ? 215 : 150;
  const showEdgeLabels =
    !workspace && shouldShowPerspectiveIngestGraphEdgeLabels(nodes, edges);
  const positions = new Map(
    nodes.map((node, index) => {
      const angle = (Math.PI * 2 * index) / Math.max(nodes.length, 1) - Math.PI / 2;
      return [
        node.id,
        {
          x: centerX + Math.cos(angle) * radiusX,
          y: centerY + Math.sin(angle) * radiusY,
        },
      ] as const;
    }),
  );

  return (
    <svg
      className={`ingest-constellation-svg${workspace ? " is-workspace" : ""}`}
      viewBox={`0 0 ${width} ${height}`}
      role="img"
      aria-label="Perspective ingest node-edge graph"
    >
      <title>Perspective ingest node-edge graph</title>
      <g aria-label="Perspective ingest graph edges">
        {edges.map((edge) => {
          const sourcePosition = positions.get(edge.source);
          const targetPosition = positions.get(edge.target);
          if (!sourcePosition || !targetPosition) return null;

          return (
            <g
              className="ingest-constellation-edge"
              key={edge.id}
              aria-label={`${edge.type}: ${edge.summary}`}
            >
              <title>{`${edge.type}: ${edge.summary}`}</title>
              <line
                x1={sourcePosition.x}
                y1={sourcePosition.y}
                x2={targetPosition.x}
                y2={targetPosition.y}
              />
              {showEdgeLabels ? (
                <text
                  x={(sourcePosition.x + targetPosition.x) / 2}
                  y={(sourcePosition.y + targetPosition.y) / 2 - 4}
                >
                  {formatPerspectiveIngestGraphEdgeLabel(edge.type)}
                </text>
              ) : null}
            </g>
          );
        })}
      </g>
      <g aria-label="Perspective ingest graph nodes">
        {nodes.map((node) => {
          const position = positions.get(node.id) ?? { x: centerX, y: centerY };
          const selected = node.id === selectedNodeId;
          const displayLabel = formatPerspectiveIngestGraphNodeLabel(
            node.label,
            node.type,
          );
          const gravityPreviewMarks = gravityPreviewNodeMarksById[node.id] ?? [];
          const gravityPreviewClassName =
            gravityPreviewMarks.length > 0
              ? ` is-gravity-preview-marked ${gravityPreviewMarks
                  .map((mark) => getManualGravityPreviewMarkClassName(mark))
                  .join(" ")}`
              : "";
          const gravityPreviewBadgeLabel = gravityPreviewMarks
            .map((mark) => mark.slice(0, 1).toUpperCase())
            .join("");

          return (
            <g
              className={`ingest-constellation-node${selected ? " selected" : ""}${gravityPreviewClassName}`}
              key={node.id}
              role="button"
              tabIndex={0}
              aria-label={`${node.label}, ${node.type}`}
              aria-pressed={selected}
              onClick={() => onSelectNode(node.id)}
              onKeyDown={(event) => {
                if (event.key === "Enter" || event.key === " ") {
                  event.preventDefault();
                  onSelectNode(node.id);
                }
              }}
            >
              <title>{`${node.label}, ${node.type}`}</title>
              <circle cx={position.x} cy={position.y} r={selected ? 25 : 22} />
              {gravityPreviewMarks.length > 0 ? (
                <text
                  className="gravity-preview-node-badge"
                  x={position.x}
                  y={position.y - 29}
                >
                  {gravityPreviewBadgeLabel}
                </text>
              ) : null}
              <text x={position.x} y={position.y + 42}>
                {displayLabel}
              </text>
            </g>
          );
        })}
      </g>
    </svg>
  );
}

function shouldShowPerspectiveIngestGraphEdgeLabels(
  nodes: PerspectiveIngestConstellationNode[],
  edges: PerspectiveIngestConstellationEdge[],
) {
  return nodes.length <= 8 && edges.length <= 10;
}

function formatPerspectiveIngestGraphNodeLabel(label: string, type?: string) {
  const compactLabels: Record<string, string> = {
    blocker_risk: "Risk",
    changed_files: "Files",
    decision: "Fixture decision",
    final_report: "Final report",
    next_move: "Next step",
    packet: "Review packets",
    product_concept: "Preview concept",
    source: "Sample record",
    unresolved_tension: "Limitation",
    user_intent: "User goal",
    validation: "Validation",
    validation_report: "Validation",
    work_context: "Work context",
    work_unit: "Work",
  };

  if (type && compactLabels[type]) return compactLabels[type];
  if (label.length <= 16) return label;

  return `${label.slice(0, 13).trim()}...`;
}

function formatPerspectiveIngestGraphEdgeLabel(
  type: PerspectiveIngestConstellationEdge["type"],
) {
  const labels: Record<PerspectiveIngestConstellationEdge["type"], string> = {
    belongs_to: "belongs",
    conflicts_with: "conflict",
    depends_on: "depends",
    derived_from: "derived",
    evidence_for: "evidence",
    next_candidate: "next",
    refines: "refines",
    supports: "supports",
    validates: "validates",
    warns_against: "warns",
  };

  return labels[type];
}

